import numpy as np
cimport cython
cimport numpy as np

DTYPE = np.float

ctypedef np.float_t DTYPE_t


@cython.boundscheck(False)
@cython.wraparound(False)
def dither_floydsteinberg(np.ndarray[DTYPE_t, ndim=2] im):
    """
          p   7
      3   5   1

    1/16
    """
    assert im.dtype == DTYPE

    cdef int rows = im.shape[0]
    cdef int cols = im.shape[1]
    cdef DTYPE_t old, error
    cdef int i, j

    for i in range(rows):
        for j in range(cols):
            old = im[i, j]
            im[i, j] = 255 if old > 127 else 0
            error = old - im[i, j]

            if j + 1 < cols:
                im[i    , j + 1] = im[i    , j + 1] + error * (7/16.)
            if i + 1 < rows:
                if j - 1 >= 0:
                    im[i + 1, j - 1] = im[i + 1, j - 1] + error * (3/16.)
                im[i + 1, j    ] = im[i + 1, j    ] + error * (5/16.)
                if j + 1 < cols:
                    im[i + 1, j + 1] = im[i + 1, j + 1] + error * (1/16.)


@cython.boundscheck(False)
@cython.wraparound(False)
def dither_atkinson(np.ndarray[DTYPE_t, ndim=2] im):
    """
          p   1   1
      1   1   1
          1

    1/8 (reduced color bleed)
    """
    assert im.dtype == DTYPE

    cdef int rows = im.shape[0]
    cdef int cols = im.shape[1]
    cdef DTYPE_t old, error
    cdef int i, j

    for i in range(rows):
        for j in range(cols):
            old = im[i, j]
            im[i, j] = 255 if old > 127 else 0
            error = (old - im[i, j]) / 8.

            if j + 1 < cols:
                im[i, j + 1] = im[i, j + 1] + error
                if j + 2 < cols:
                    im[i, j + 2] = im[i, j + 2] + error
            if i + 1 < rows:
                if j - 1 >= 0:
                    im[i + 1, j - 1] = im[i + 1, j - 1] + error
                im[i + 1, j] = im[i + 1, j] + error
                if j + 1 < cols:
                    im[i + 1, j + 1] = im[i + 1, j + 1] + error
                if i + 2 < rows:
                    im[i + 2, j] = im[i + 2, j] + error

import cython
from cython.parallel import prange


@cython.boundscheck(False)
@cython.wraparound(False)
cpdef double[:, ::1] add_matrix(
        double[:, ::1] A,
        double[:, ::1] B
):
    cdef int m_a = A.shape[0]
    cdef int n_a = A.shape[1]
    cdef int m_b = B.shape[0]
    cdef int n_b = B.shape[1]
    cdef int i, j

    if m_a != m_b or n_a != n_b:
        raise ValueError("A and B must be the same shape got A: [{}, {}] and B: [{}, {}}]".format(m_a, n_a, m_b, n_b))

    for i in prange(m_a, nogil=True):
        for j in prange(n_a):
            A[i, j] += B[i, j]

    return A

